// Parse Phase 1 Instructions
const directorResponse = $json;
const completeContext = $('Initialize Complete Workflow').first().json.completeWorkflowContext;

const instructionData = directorResponse.data;

if (!instructionData || !instructionData.instruction) {
  return [{
    instructionText: "Error: No valid Phase 1 instructions received",
    error: true,
    task_id: "phase1_error"
  }];
}

const instruction = instructionData.instruction;
let instructionText = '';

instructionText += `# PHASE 1: IDEA CATEGORIZATION (Part of Complete Workflow)\n\n`;
instructionText += `## COMPLETE WORKFLOW CONTEXT\n`;
instructionText += `- Session ID: ${completeContext.sessionId}\n`;
instructionText += `- Total Workflow: Phase 1 (Categorization) → Phase 2 (Database Creation)\n`;
instructionText += `- Current Phase: ${completeContext.currentPhase} → phase1_categorization\n\n`;

instructionText += `## PHASE 1 OBJECTIVE\n`;
instructionText += `Retrieve ideas from the source database and categorize them for database routing.\n`;
instructionText += `Each idea will be analyzed and assigned to: projects, knowledge, or journal databases.\n\n`;

if (instruction.parameters) {
  instructionText += `## TASK PARAMETERS\n`;
  Object.entries(instruction.parameters).forEach(([key, value]) => {
    instructionText += `- ${key}: ${value}\n`;
  });
  instructionText += '\n';
}

if (instructionData.categorization_methodology) {
  instructionText += `## CATEGORIZATION METHODOLOGY\n`;

  if (instructionData.categorization_methodology.multi_idea_parsing_rules) {
    instructionText += `### MULTI-IDEA PARSING:\n`;
    instructionData.categorization_methodology.multi_idea_parsing_rules.forEach(rule => {
      instructionText += `- ${rule}\n`;
    });
    instructionText += '\n';
  }

  if (instructionData.categorization_methodology.database_routing_criteria) {
    instructionText += `### DATABASE ROUTING CRITERIA:\n`;
    Object.entries(instructionData.categorization_methodology.database_routing_criteria).forEach(([key, criteria]) => {
      instructionText += `**${key.toUpperCase()}:**\n`;
      if (criteria.description) instructionText += `- ${criteria.description}\n`;
      if (criteria.keywords) instructionText += `- Keywords: ${criteria.keywords.join(', ')}\n`;
      instructionText += '\n';
    });
  }
}

instructionText += `## EXECUTION STEPS\n`;
instructionText += `1. Use get_ideas tool to retrieve ${instruction.parameters?.limit || 3} ideas with status='Not Started'\n`;
instructionText += `2. Analyze each idea's content to identify distinct concepts/projects\n`;
instructionText += `3. Apply categorization methodology to assign database routes\n`;
instructionText += `4. Update source ideas to 'Done' status\n`;
instructionText += `5. Return categorized results for Phase 2 database creation\n\n`;

instructionText += `## EXPECTED OUTPUT FOR PHASE 2\n`;
instructionText += `Return results with categorized_ideas array containing:\n`;
instructionText += `{\n`;
instructionText += `  "agent_id": "notion",\n`;
instructionText += `  "task_id": "${instructionData.task_id}",\n`;
instructionText += `  "phase": "categorization_complete",\n`;
instructionText += `  "results": {\n`;
instructionText += `    "ideas_processed": [\n`;
instructionText += `      {\n`;
instructionText += `        "idea_id": "source_id",\n`;
instructionText += `        "title": "extracted_title",\n`;
instructionText += `        "original_content": "full_content",\n`;
instructionText += `        "categorization": {\n`;
instructionText += `          "database": "projects|knowledge|journal",\n`;
instructionText += `          "database_id": "${completeContext.phase2Config.target_databases.projects || 'target_db_id'}",\n`;
instructionText += `          "category": "specific_category",\n`;
instructionText += `          "priority": "High|Medium|Low",\n`;
instructionText += `          "tags": ["array", "of", "tags"]\n`;
instructionText += `        }\n`;
instructionText += `      }\n`;
instructionText += `    ]\n`;
instructionText += `  },\n`;
instructionText += `  "status": {\n`;
instructionText += `    "success": true,\n`;
instructionText += `    "next_phase": "database_creation_required"\n`;
instructionText += `  }\n`;
instructionText += `}\n\n`;

instructionText += `**This is Phase 1 of a 2-phase workflow. Your results will feed directly into Phase 2 for database creation.**\n\n`;
instructionText += `**BEGIN PHASE 1 CATEGORIZATION NOW**\n`;

return [{
  instructionText,
  task_id: instructionData.task_id,
  phase: 'phase1_categorization',
  completeContext,
  directorResponse: instructionData
}];

// Process Phase 1 Results and Prepare for Phase 2
const phase1Output = $json;
const completeContext = $('Parse Phase 1 Instructions').first().json.completeContext;

// Parse Phase 1 results
let phase1Results;
try {
  const outputText = phase1Output.output || phase1Output.text || JSON.stringify(phase1Output);
  console.log('Phase 1 Output:', outputText.substring(0, 500));

  const jsonMatch = outputText.match(/\{[\s\S]*\}/);

  if (jsonMatch) {
    phase1Results = JSON.parse(jsonMatch[0]);
  } else {
    // Fallback structure
    phase1Results = {
      agent_id: 'notion',
      task_id: 'phase1_fallback',
      phase: 'categorization_complete',
      timestamp: new Date().toISOString(),
      results: {
        ideas_processed: [],
        summary: { total_processed: 0 }
      },
      status: {
        success: false,
        next_phase: 'error_review'
      }
    };
  }
} catch (error) {
  console.error('Error parsing Phase 1 results:', error.message);
  phase1Results = {
    error: error.message,
    status: { success: false, next_phase: 'error_review' }
  };
}

// Validate categorized ideas for Phase 2
const categorizedIdeas = phase1Results.results?.ideas_processed || [];
const validIdeas = categorizedIdeas.filter(idea => 
  idea.categorization && 
  idea.categorization.database && 
  ['projects', 'knowledge', 'journal'].includes(idea.categorization.database)
);

// Enhance categorized ideas with target database IDs
const enhancedIdeas = validIdeas.map(idea => ({
  ...idea,
  categorization: {
    ...idea.categorization,
    database_id: completeContext.phase2Config.target_databases[idea.categorization.database] || 'unknown_db_id'
  }
}));

// Create Phase 1 completion summary
const phase1Summary = {
  phase1_complete: true,
  execution_time_ms: Date.now() - new Date(completeContext.startTime).getTime(),
  ideas_categorized: enhancedIdeas.length,
  database_distribution: {
    projects: enhancedIdeas.filter(i => i.categorization.database === 'projects').length,
    knowledge: enhancedIdeas.filter(i => i.categorization.database === 'knowledge').length,
    journal: enhancedIdeas.filter(i => i.categorization.database === 'journal').length
  },
  ready_for_phase2: enhancedIdeas.length > 0 && phase1Results.status?.success
};

// Prepare Phase 2 context
const phase2Context = {
  sessionId: completeContext.sessionId,
  workflowType: 'complete_workflow_phase2',
  currentPhase: 'phase2_database_creation',
  phase2StartTime: new Date().toISOString(),
  context_id: `${completeContext.sessionId}_phase1_complete`,
  categorized_ideas: enhancedIdeas,
  target_databases: completeContext.phase2Config.target_databases,
  phase1_results: phase1Summary
};

return [{
  phase1Complete: true,
  readyForPhase2: phase1Summary.ready_for_phase2,
  phase1Summary,
  phase2Context,
  categorizedIdeas: enhancedIdeas,
  originalPhase1Output: outputText || 'No output captured',
  transitionData: {
    ideas_to_create: enhancedIdeas.length,
    databases_targeted: Object.keys(phase2Context.target_databases),
    phase1_success: phase1Results.status?.success || false
  }
}];

// Parse Phase 2 Instructions for Database Creation
const directorResponse = $json;
const phase2Context = $('Begin Phase 2: Database Creation').first().json.phase2Context;

const instructionData = directorResponse.data;

if (!instructionData || !instructionData.instruction) {
  return [{
    instructionText: "Error: No valid Phase 2 instructions received",
    error: true,
    task_id: "phase2_error"
  }];
}

const instruction = instructionData.instruction;
const categorizedIdeas = phase2Context.categorized_ideas || [];

let instructionText = '';

instructionText += `# PHASE 2: DATABASE ITEM CREATION (Complete Workflow)\n\n`;
instructionText += `## COMPLETE WORKFLOW STATUS\n`;
instructionText += `- ✅ Phase 1: Categorization Complete (${categorizedIdeas.length} ideas processed)\n`;
instructionText += `- 🔄 Phase 2: Database Creation In Progress\n`;
instructionText += `- Session ID: ${phase2Context.sessionId}\n`;
instructionText += `- Context ID: ${phase2Context.context_id}\n\n`;

instructionText += `## PHASE 1 RESULTS SUMMARY\n`;
if (phase2Context.phase1_results) {
  const p1 = phase2Context.phase1_results;
  instructionText += `- Ideas Categorized: ${p1.ideas_categorized}\n`;
  instructionText += `- Projects: ${p1.database_distribution.projects}\n`;
  instructionText += `- Knowledge: ${p1.database_distribution.knowledge}\n`;
  instructionText += `- Journal: ${p1.database_distribution.journal}\n`;
  instructionText += `- Phase 1 Execution Time: ${p1.execution_time_ms}ms\n\n`;
}

instructionText += `## PHASE 2 OBJECTIVE\n`;
instructionText += `Create new database items from the ${categorizedIdeas.length} categorized ideas.\n`;
instructionText += `Use generic Notion database endpoints to create properly structured items in each target database.\n\n`;

instructionText += `## TARGET DATABASES\n`;
if (phase2Context.target_databases) {
  Object.entries(phase2Context.target_databases).forEach(([type, id]) => {
    const count = categorizedIdeas.filter(i => i.categorization.database === type).length;
    instructionText += `- **${type.toUpperCase()}** (${id}): ${count} items to create\n`;
  });
  instructionText += '\n';
}

instructionText += `## CATEGORIZED IDEAS TO CREATE\n`;
categorizedIdeas.forEach((idea, index) => {
  instructionText += `### ${index + 1}. ${idea.title}\n`;
  instructionText += `- **Target**: ${idea.categorization.database} (${idea.categorization.database_id})\n`;
  instructionText += `- **Category**: ${idea.categorization.category}\n`;
  instructionText += `- **Priority**: ${idea.categorization.priority}\n`;
  instructionText += `- **Tags**: [${idea.categorization.tags.join(', ')}]\n`;
  instructionText += `- **Content**: ${idea.original_content.substring(0, 100)}...\n\n`;
});

instructionText += `## EXECUTION STEPS\n`;
instructionText += `For each categorized idea:\n`;
instructionText += `1. **Get Schema**: Call /api/databases/{database_id}/schema\n`;
instructionText += `2. **Create Item**: POST /api/databases/{database_id}/pages with proper properties\n`;
instructionText += `3. **Verify Creation**: Confirm successful creation\n`;
instructionText += `4. **Log Results**: Record success/failure details\n\n`;

instructionText += `## EXPECTED FINAL OUTPUT\n`;
instructionText += `Return comprehensive workflow completion results:\n`;
instructionText += `{\n`;
instructionText += `  "agent_id": "notion",\n`;
instructionText += `  "task_id": "${instructionData.task_id}",\n`;
instructionText += `  "phase": "complete_workflow_finished",\n`;
instructionText += `  "complete_workflow_results": {\n`;
instructionText += `    "phase1_summary": "categorization results",\n`;
instructionText += `    "phase2_results": {\n`;
instructionText += `      "database_items_created": ["array of created items"],\n`;
instructionText += `      "creation_summary": {\n`;
instructionText += `        "total_attempted": ${categorizedIdeas.length},\n`;
instructionText += `        "successful_creations": "number",\n`;
instructionText += `        "failed_creations": "number"\n`;
instructionText += `      }\n`;
instructionText += `    },\n`;
instructionText += `    "workflow_performance": {\n`;
instructionText += `      "total_execution_time_ms": "duration",\n`;
instructionText += `      "phase1_time_ms": "${phase2Context.phase1_results?.execution_time_ms || 0}",\n`;
instructionText += `      "phase2_time_ms": "duration"\n`;
instructionText += `    }\n`;
instructionText += `  },\n`;
instructionText += `  "status": {\n`;
instructionText += `    "success": "boolean",\n`;
instructionText += `    "workflow_complete": true,\n`;
instructionText += `    "next_phase": "workflow_complete"\n`;
instructionText += `  }\n`;
instructionText += `}\n\n`;

instructionText += `**This completes the entire Director + Notion workflow. Execute Phase 2 database creation now.**\n`;

return [{
  instructionText,
  task_id: instructionData.task_id,
  phase: 'phase2_database_creation',
  categorizedIdeas,
  targetDatabases: phase2Context.target_databases,
  phase2Context
}];

// Process Complete Workflow Results
const phase2Output = $json;
const phase2Context = $('Parse Phase 2 Instructions').first().json.phase2Context;
const completeStartTime = $('Initialize Complete Workflow').first().json.completeWorkflowContext.startTime;

// Parse final results
let completeResults;
try {
  const outputText = phase2Output.output || phase2Output.text || JSON.stringify(phase2Output);
  console.log('Complete Workflow Final Output:', outputText.substring(0, 500));

  const jsonMatch = outputText.match(/\{[\s\S]*\}/);

  if (jsonMatch) {
    completeResults = JSON.parse(jsonMatch[0]);
  } else {
    // Fallback complete results
    completeResults = {
      agent_id: 'notion',
      task_id: 'complete_workflow_fallback',
      phase: 'complete_workflow_finished',
      complete_workflow_results: {
        phase1_summary: phase2Context.phase1_results,
        phase2_results: {
          database_items_created: [],
          creation_summary: { total_attempted: 0, successful_creations: 0, failed_creations: 0 }
        }
      },
      status: { success: false, workflow_complete: false }
    };
  }
} catch (error) {
  console.error('Error parsing complete workflow results:', error.message);
  completeResults = {
    error: error.message,
    status: { success: false, workflow_complete: false }
  };
}

// Calculate total workflow metrics
const totalWorkflowTime = Date.now() - new Date(completeStartTime).getTime();
const phase1Time = phase2Context.phase1_results?.execution_time_ms || 0;
const phase2Time = totalWorkflowTime - phase1Time;

// Create comprehensive workflow summary
const workflowSummary = {
  workflow_complete: true,
  session_id: phase2Context.sessionId,
  total_execution_time_ms: totalWorkflowTime,

  phase1_results: {
    ideas_categorized: phase2Context.phase1_results?.ideas_categorized || 0,
    execution_time_ms: phase1Time,
    database_distribution: phase2Context.phase1_results?.database_distribution || {},
    success: true
  },

  phase2_results: {
    items_created: completeResults.complete_workflow_results?.phase2_results?.database_items_created?.length || 0,
    creation_success_rate: 0,
    execution_time_ms: phase2Time,
    success: completeResults.status?.success || false
  },

  overall_performance: {
    total_ideas_processed: phase2Context.categorized_ideas?.length || 0,
    end_to_end_success: completeResults.status?.workflow_complete || false,
    phase1_to_phase2_success_rate: 1.0, // Assuming Phase 1 succeeded if we got here
    databases_targeted: Object.keys(phase2Context.target_databases || {}).length
  }
};

// Update success rate if we have creation data
if (completeResults.complete_workflow_results?.phase2_results?.creation_summary) {
  const summary = completeResults.complete_workflow_results.phase2_results.creation_summary;
  workflowSummary.phase2_results.creation_success_rate = 
    summary.total_attempted > 0 ? summary.successful_creations / summary.total_attempted : 0;
}

return [{
  completeWorkflowFinished: true,
  workflowSummary,
  finalResults: completeResults,

  // Director context update payload
  directorFinalUpdate: {
    context_id: phase2Context.context_id,
    phase: 'complete_workflow_finished',
    agent_response: completeResults,
    workflow_summary: workflowSummary,
    timestamp: new Date().toISOString()
  },

  // Summary for user
  executionSummary: {
    success: workflowSummary.overall_performance.end_to_end_success,
    total_time_seconds: Math.round(totalWorkflowTime / 1000),
    phase1_time_seconds: Math.round(phase1Time / 1000),
    phase2_time_seconds: Math.round(phase2Time / 1000),
    ideas_processed: workflowSummary.overall_performance.total_ideas_processed,
    database_items_created: workflowSummary.phase2_results.items_created,
    databases_used: Object.keys(phase2Context.target_databases || {})
  },

  rawOutput: outputText || 'No output captured'
}];
